#!/usr/bin/env node
// Local calculator MCP stub. Accepts a `calc/eval` method with { expr }
// and returns the numeric result. Uses Function() in a tightly scoped
// way; no I/O, no shell.
process.stdin.setEncoding('utf8');
let buf = '';
process.stdin.on('data', (chunk) => {
  buf += chunk;
  let idx;
  while ((idx = buf.indexOf('\n')) >= 0) {
    const line = buf.slice(0, idx);
    buf = buf.slice(idx + 1);
    if (!line.trim()) continue;
    let msg;
    try { msg = JSON.parse(line); } catch { continue; }
    if (msg.method === 'initialize') {
      process.stdout.write(JSON.stringify({ jsonrpc: '2.0', id: msg.id, result: { protocolVersion: '0.1.0', capabilities: {}, serverInfo: { name: 'calculator', version: '0.1.0' } } }) + '\n');
      continue;
    }
    const expr = msg?.params?.expr || '';
    if (!/^[-+*/().\d\s%]+$/.test(expr)) {
      process.stdout.write(JSON.stringify({ jsonrpc: '2.0', id: msg.id, error: { code: -32602, message: 'unsafe expression' } }) + '\n');
      continue;
    }
    let result;
    try { result = Function('"use strict"; return (' + expr + ');')(); }
    catch (e) { process.stdout.write(JSON.stringify({ jsonrpc: '2.0', id: msg.id, error: { code: -32603, message: e.message } }) + '\n'); continue; }
    process.stdout.write(JSON.stringify({ jsonrpc: '2.0', id: msg.id, result }) + '\n');
  }
});
